              type="text"
              value={form.username}
              onChange={(e) => f("username", e.target.value)}
            />
          </div>
          <div className="auth-field" style={{ gridColumn: "1/-1" }}>
            <label>Email</label>
            <input
              type="email"
              value={form.email}
              onChange={(e) => f("email", e.target.value)}
            />
          </div>
          <div className="auth-field">
            <label>Status</label>
