              value={form.status}
              onChange={(e) => f("status", e.target.value)}
            >
              <option value="active">Active</option>
              <option value="inactive">Inactive</option>
            </select>
          </div>
        </div>
        <div className="modal-actions">
          <button type="button" className="btn btn-ghost" onClick={onClose}>
            Cancel
          </button>
          <button
            type="submit"
            className={`btn btn-primary${loading ? " btn-loading" : ""}`}
            disabled={loading}
          >
            {loading ? "Saving…" : "Save changes"}
          </button>
        </div>
      </form>
    </Modal>
  );
}

// ══════════════════════════════════════════════════════════════════
//  TRIP LOGS (shared — admin sees all, driver sees own)
// ══════════════════════════════════════════════════════════════════
function LogsPage({ user, onLogout }) {
  const isAdmin = user?.role === "admin";
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [vehicleFilter, setVehicleFilter] = useState("");
  const [editLog, setEditLog] = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [toast, setToast] = useState({ show: false, msg: "", type: "success" });

  const showToast = (msg, type = "success") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  const fetchLogs = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/driver-log`, {
        headers: authHeaders(),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      const data = await res.json();
      setLogs(Array.isArray(data) ? data : []);
    } catch {
      showToast("Could not load logs.", "error");
    } finally {
      setLoading(false);
    }
  }, [onLogout]);

  useEffect(() => {
    fetchLogs();
  }, [fetchLogs]);

  const filtered = logs.filter((l) => {
    const s = search.toLowerCase();
    const match =
      !s ||
      l.DRIVER_NAME?.toLowerCase().includes(s) ||
      l.VEHICLE_NUMBER?.toLowerCase().includes(s) ||
      l.PURPOSE?.toLowerCase().includes(s);
    const vm = !vehicleFilter || l.VEHICLE_TYPE === vehicleFilter;
    return match && vm;
  });

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this log?")) return;
    try {
      const res = await fetch(`${API_URL}/api/driver-log/${id}`, {
        method: "DELETE",
        headers: authHeaders(),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      if (res.ok) {
        setLogs((l) => l.filter((x) => x.ID !== id));
        showToast("Log deleted.");
      } else showToast("Failed to delete.", "error");
    } catch {
      showToast("Server error.", "error");
    }
  };

  const exportCSV = () => {
    const headers = [
      "Driver Name",
      "Purpose",
      "Vehicle Type",
      "Vehicle Number",
      "In Time",
      "Out Time",
      "Duration",
      "In KM",
      "Out KM",
      "KM Diff",
    ];
    const rows = filtered.map((l) => [
      l.DRIVER_NAME,
      l.PURPOSE,
      l.VEHICLE_TYPE,
      l.VEHICLE_NUMBER,
      new Date(l.IN_TIME).toLocaleString(),
      new Date(l.OUT_TIME).toLocaleString(),
      l.TIME_DIFFERENCE,
      l.IN_KM,
      l.OUT_KM,
      l.KM_DIFFERENCE,
    ]);
    const csv = [headers, ...rows]
      .map((r) => r.map((v) => `"${v ?? ""}"`).join(","))
      .join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `driver-logs-${Date.now()}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div>
      <div className="page-toolbar">
        <div className="search-row">
          <input
            className="search-input"
            type="text"
            placeholder="Search driver, vehicle, purpose…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <select
            className="filter-select"
            value={vehicleFilter}
            onChange={(e) => setVehicleFilter(e.target.value)}
          >
            <option value="">All vehicles</option>
            {VEHICLE_TYPES.map((v) => (
              <option key={v.label} value={v.label}>
                {v.icon} {v.label}
              </option>
            ))}
          </select>
          <button className="btn btn-ghost" onClick={exportCSV}>
            <Icon path={ICONS.upload} size={13} /> Export CSV
          </button>
          <button className="btn btn-primary" onClick={() => setShowAdd(true)}>
            + Log trip
          </button>
        </div>
      </div>
      <div className="table-card">
        {loading ? (
          <div className="table-empty">Loading logs…</div>
        ) : filtered.length === 0 ? (
          <div className="table-empty">No logs found.</div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Driver</th>
                  <th>Vehicle</th>
                  <th>Plate</th>
                  <th>Purpose</th>
                  <th>In time</th>
                  <th>Duration</th>
                  <th>KM</th>
                  {isAdmin && <th>Actions</th>}
                </tr>
              </thead>
              <tbody>
                {filtered.map((l) => (
                  <tr key={l.ID}>
                    <td>
                      <div className="cell-user">
                        <div
                          className="u-avatar av-driver"
                          style={{ width: 26, height: 26, fontSize: 10 }}
                        >
                          {getInitials(l.DRIVER_NAME)}
                        </div>
                        <span>{l.DRIVER_NAME}</span>
                      </div>
                    </td>
                    <td>
                      <span className="badge badge-purple">
                        {
                          VEHICLE_TYPES.find((v) => v.label === l.VEHICLE_TYPE)
                            ?.icon
                        }{" "}
                        {l.VEHICLE_TYPE}
                      </span>
                    </td>
                    <td>
                      <span className="mono-badge">{l.VEHICLE_NUMBER}</span>
                    </td>
                    <td>{l.PURPOSE}</td>
                    <td className="text-muted">
                      {new Date(l.IN_TIME).toLocaleString()}
                    </td>
                    <td>
                      <span className="badge badge-amber">
                        {l.TIME_DIFFERENCE}
                      </span>
                    </td>
                    <td>
                      <span className="badge badge-green">
                        {l.KM_DIFFERENCE} km
                      </span>
                    </td>
                    {isAdmin && (
                      <td>
                        <div className="action-row">
                          <button
                            className="icon-btn"
                            onClick={() => setEditLog(l)}
                            title="Edit"
                          >
                            <Icon path={ICONS.edit} size={13} />
                          </button>
                          <button
                            className="icon-btn icon-btn-danger"
                            onClick={() => handleDelete(l.ID)}
                            title="Delete"
                          >
                            <Icon path={ICONS.trash} size={13} />
                          </button>
                        </div>
                      </td>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        <div className="table-footer">
          {filtered.length} record{filtered.length !== 1 ? "s" : ""}
        </div>
      </div>
      {showAdd && (
        <AddLogModal
          onClose={() => setShowAdd(false)}
          onSaved={() => {
            setShowAdd(false);
            fetchLogs();
            showToast("Trip logged!");
          }}
          onLogout={onLogout}
        />
      )}
      {editLog && isAdmin && (
        <EditLogModal
          log={editLog}
          onClose={() => setEditLog(null)}
          onSaved={() => {
            setEditLog(null);
            fetchLogs();
            showToast("Log updated!");
          }}
          onLogout={onLogout}
        />
      )}
      <Toast toast={toast} />
    </div>
  );
}

function AddLogModal({ onClose, onSaved, onLogout }) {
  const [form, setForm] = useState({
    driverName: "",
    purpose: "",
    vehicleType: "",
    vehicleNumber: "",
    inTime: "",
    outTime: "",
    inKm: "",
    outKm: "",
  });
  const [loading, setLoading] = useState(false);
  const timeDiff = calcTimeDiff(form.inTime, form.outTime);
  const kmDiff = parseFloat(form.outKm) - parseFloat(form.inKm);
  const f = (field, val) => setForm((prev) => ({ ...prev, [field]: val }));

  const handleSubmit = async (ev) => {
    ev.preventDefault();
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/driver-log`, {
        method: "POST",
        headers: authHeaders(),
        body: JSON.stringify({
          driver_name: form.driverName.trim(),
          purpose: form.purpose.trim(),
          vehicle_type: form.vehicleType,
          vehicle_number: form.vehicleNumber.trim().toUpperCase(),
          in_time: form.inTime,
          out_time: form.outTime,
          time_difference: timeDiff,
          in_km: parseFloat(form.inKm),
          out_km: parseFloat(form.outKm),
          km_difference: isNaN(kmDiff) ? 0 : parseFloat(kmDiff.toFixed(1)),
        }),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      if (res.ok) onSaved();
    } catch {
      console.error("Submit failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal title="Log a new trip" onClose={onClose} size="lg">
      <form onSubmit={handleSubmit} noValidate>
        <div className="form-grid-2">
          <div className="auth-field">
            <label>Driver name *</label>
            <input
              type="text"
