              {VEHICLE_TYPES.map((v) => (
                <div
                  key={v.label}
                  className={`v-opt${form.vehicleType === v.label ? " v-sel" : ""}`}
                  onClick={() => f("vehicleType", v.label)}
                >
                  <span className="v-icon">{v.icon}</span>
                  {v.label}
                </div>
              ))}
            </div>
          </div>
          <div className="auth-field" style={{ gridColumn: "1/-1" }}>
