              placeholder="0"
              min="0"
            />
          </div>
          <div className="auth-field">
            <label>Duration (auto)</label>
            <input readOnly value={timeDiff} className="inp-readonly" />
          </div>
          <div className="auth-field">
            <label>KM diff (auto)</label>
