function BulkUploadPage({ onLogout }) {
  const [preview, setPreview] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [toast, setToast] = useState({ show: false, msg: "", type: "success" });
  const inputRef = useRef();

  const showToast = (msg, type = "success") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  // ✅ DOWNLOAD TEMPLATE LOGIC
  const downloadTemplate = () => {
    const headers = [
      "driver_name",
      "purpose",
      "vehicle_type",
      "vehicle_number",
      "in_time",
      "out_time",
      "in_km",
      "out_km",
    ];

    const sampleRows = [
      [
        "Ravi Kumar",
        "Office Visit",
        "Car",
        "GJ01AB1234",
        "2026-04-19T09:00",
        "2026-04-19T12:30",
        "1200",
        "1250",
      ],
      [
        "Priya Shah",
        "Client Meeting",
        "Bike",
        "GJ05XY5678",
        "2026-04-19T10:00",
        "2026-04-19T11:30",
        "800",
        "820",
      ],
    ];

    const csvContent = [
      headers.join(","),
      ...sampleRows.map((row) => row.join(",")),
    ].join("\n");

    const blob = new Blob([csvContent], {
      type: "text/csv;charset=utf-8;",
    });

    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "driver_log_template.csv"); // 👈 filename
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleFile = async (file) => {
    if (!file) return;
    const ext = file.name.split(".").pop().toLowerCase();

    if (!["csv", "xlsx", "xls"].includes(ext)) {
      showToast("Only CSV and Excel files are supported.", "error");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    try {
      const res = await fetch(`${API_URL}/api/driver-log/bulk/preview`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
        body: formData,
      });

      if (res.status === 401) {
        onLogout();
        return;
      }

      const data = await res.json();
      setPreview(data);
    } catch {
      showToast("Could not parse file.", "error");
    }
  };

  const handleConfirmUpload = async () => {
    if (!preview?.rows?.length) return;

    setUploading(true);

    try {
      const res = await fetch(`${API_URL}/api/driver-log/bulk`, {
        method: "POST",
        headers: authHeaders(),
        body: JSON.stringify({ rows: preview.rows }),
      });

      if (res.status === 401) {
        onLogout();
        return;
      }

      const data = await res.json();
      showToast(`${data.inserted || 0} records uploaded successfully!`);
      setPreview(null);
    } catch {
      showToast("Upload failed.", "error");
    } finally {
      setUploading(false);
    }
  };

  return (
    <div>
      <div className="upload-card">
        {/* ✅ DOWNLOAD TEMPLATE BUTTON */}
        <button
          className="btn btn-secondary"
          style={{ marginBottom: 12 }}
          onClick={downloadTemplate}
        >
          Download Template
        </button>

        {/* Upload Zone */}
        <div
          className="upload-zone"
          onClick={() => inputRef.current.click()}
          onDragOver={(e) => e.preventDefault()}
          onDrop={(e) => {
            e.preventDefault();
            handleFile(e.dataTransfer.files[0]);
          }}
        >
          <p>
            Drop your Excel or CSV file here, or{" "}
            <span style={{ color: "var(--accent)" }}>browse</span>
          </p>
          <small>Supports .xlsx, .xls, .csv — max 10 MB</small>
        </div>

        <input
          ref={inputRef}
          type="file"
          accept=".csv,.xlsx,.xls"
          style={{ display: "none" }}
          onChange={(e) => handleFile(e.target.files[0])}
        />

        {/* Required Columns */}
        <div className="required-cols">
          <div className="req-cols-title">Required column headers</div>
          <div className="req-cols-list">
            {[
              "driver_name",
              "purpose",
              "vehicle_type",
              "vehicle_number",
              "in_time",
              "out_time",
              "in_km",
              "out_km",
            ].map((c) => (
              <span key={c} className="badge badge-purple">
                {c}
              </span>
            ))}
          </div>

          <div className="req-cols-note">
            <code>vehicle_type</code> must be one of: Car, Truck, Van, Bike,
            Bus, Other. Dates format: <code>YYYY-MM-DDTHH:MM</code>
          </div>
        </div>
      </div>

      {/* Preview Table */}
      {preview && (
        <div className="table-card" style={{ marginTop: 16 }}>
          <div className="table-card-head">
            <span className="card-title">
              Preview — {preview.rows?.length || 0} rows
            </span>

            <div style={{ display: "flex", gap: 8 }}>
              <button
                className="btn btn-ghost"
                onClick={() => setPreview(null)}
              >
                Clear
              </button>

              <button
                className={`btn btn-primary${uploading ? " btn-loading" : ""}`}
                onClick={handleConfirmUpload}
                disabled={uploading}
              >
                {uploading
                  ? "Uploading…"
                  : `Upload ${preview.rows?.length} rows`}
              </button>
            </div>
          </div>

          {/* Errors */}
          {preview.errors?.length > 0 && (
            <div className="upload-errors">
              <strong>Validation warnings:</strong>
              {preview.errors.slice(0, 5).map((e, i) => (
                <div key={i} className="upload-error-row">
                  Row {e.row}: {e.msg}
                </div>
              ))}
            </div>
          )}

          {/* Table */}
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  {preview.headers?.map((h) => (
                    <th key={h}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {preview.rows?.slice(0, 8).map((row, i) => (
                  <tr key={i}>
                    {preview.headers?.map((h) => (
                      <td key={h}>{row[h] ?? ""}</td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <Toast toast={toast} />
    </div>
  );
}

