//  PROFILE PAGE
// ══════════════════════════════════════════════════════════════════
function ProfilePage({ user, onUserUpdate, onLogout }) {
  const [tab, setTab] = useState("info");
  const [form, setForm] = useState({
    full_name: user.full_name || "",
    username: user.username || "",
    email: user.email || "",
  });
  const [pwd, setPwd] = useState({
    current_password: "",
    new_password: "",
    confirm_password: "",
  });
  const [show, setShow] = useState({ cur: false, new: false, con: false });
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState({ show: false, msg: "", type: "success" });

  const showToast = (msg, type = "success") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  const handleInfoSubmit = async (ev) => {
    ev.preventDefault();
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/auth/me`, {
        method: "PUT",
        headers: authHeaders(),
        body: JSON.stringify(form),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      const data = await res.json();
      if (res.ok) {
        const updated = { ...user, ...data.user };
        localStorage.setItem("user", JSON.stringify(updated));
        if (data.token) {
          localStorage.setItem("token", data.token);
          localStorage.setItem(
            "tokenExpiry",
            String(Date.now() + 6 * 60 * 60 * 1000),
          );
        }
        onUserUpdate(updated);
        showToast("Profile updated!");
      } else showToast(data.message || "Update failed", "error");
    } catch {
      showToast("Server error.", "error");
    } finally {
      setLoading(false);
    }
  };

  const handlePwdSubmit = async (ev) => {
    ev.preventDefault();
    if (pwd.new_password !== pwd.confirm_password) {
      showToast("Passwords do not match", "error");
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/auth/change-password`, {
        method: "PUT",
        headers: authHeaders(),
        body: JSON.stringify({
          current_password: pwd.current_password,
          new_password: pwd.new_password,
        }),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      const data = await res.json();
      if (res.ok) {
        showToast("Password changed!");
        setPwd({
          current_password: "",
          new_password: "",
          confirm_password: "",
        });
      } else showToast(data.message || "Failed", "error");
    } catch {
      showToast("Server error.", "error");
    } finally {
      setLoading(false);
    }
  };

  const isAdmin = user?.role === "admin";

  return (
    <div style={{ maxWidth: 540 }}>
      <div className="profile-header-card">
        <div
          className={`u-avatar ${isAdmin ? "av-admin" : "av-driver"}`}
          style={{ width: 56, height: 56, fontSize: 22, marginBottom: 10 }}
        >
          {getInitials(user.full_name)}
        </div>
        <div className="profile-name">{user.full_name}</div>
        <div className="profile-role-label">
          {isAdmin ? "Administrator" : "Driver"} · {user.email}
        </div>
      </div>
      <div className="profile-tabs">
        <button
          className={`ptab${tab === "info" ? " ptab-active" : ""}`}
          onClick={() => setTab("info")}
        >
          Profile info
        </button>
        <button
          className={`ptab${tab === "pwd" ? " ptab-active" : ""}`}
          onClick={() => setTab("pwd")}
        >
          Change password
        </button>
      </div>
      {tab === "info" && (
        <div className="table-card">
          <form onSubmit={handleInfoSubmit} noValidate>
            <div className="form-grid-2">
              <div className="auth-field">
                <label>Full name *</label>
                <input
                  type="text"
                  value={form.full_name}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, full_name: e.target.value }))
                  }
                />
              </div>
              <div className="auth-field">
                <label>Username *</label>
                <input
                  type="text"
                  value={form.username}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, username: e.target.value }))
                  }
                />
              </div>
              <div className="auth-field" style={{ gridColumn: "1/-1" }}>
                <label>Email *</label>
                <input
                  type="email"
                  value={form.email}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, email: e.target.value }))
                  }
                />
              </div>
            </div>
            <div className="modal-actions" style={{ marginTop: 16 }}>
              <button
                type="submit"
                className={`btn btn-primary${loading ? " btn-loading" : ""}`}
                disabled={loading}
              >
                {loading ? "Saving…" : "Save changes"}
              </button>
            </div>
          </form>
        </div>
      )}
      {tab === "pwd" && (
        <div className="table-card">
          <form onSubmit={handlePwdSubmit} noValidate>
            {[
              [
                "cur",
                "current_password",
                "Current password",
                "Enter current password",
              ],
              ["new", "new_password", "New password", "Min. 6 characters"],
              [
                "con",
                "confirm_password",
                "Confirm new password",
                "Re-enter new password",
              ],
            ].map(([k, field, label, ph]) => (
              <div className="auth-field" key={field}>
                <label>{label}</label>
                <div className="pwd-wrap">
                  <input
                    type={show[k] ? "text" : "password"}
                    value={pwd[field]}
                    placeholder={ph}
                    onChange={(e) =>
                      setPwd((p) => ({ ...p, [field]: e.target.value }))
                    }
                  />
                  <EyeBtn
                    show={show[k]}
                    toggle={() => setShow((s) => ({ ...s, [k]: !s[k] }))}
                  />
                </div>
              </div>
            ))}
            <div className="modal-actions" style={{ marginTop: 16 }}>
              <button
                type="submit"
                className={`btn btn-primary${loading ? " btn-loading" : ""}`}
                disabled={loading}
              >
                {loading ? "Changing…" : "Change password"}
              </button>
            </div>
          </form>
        </div>
      )}
      <Toast toast={toast} />
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
//  STATS BAR
// ══════════════════════════════════════════════════════════════════
function StatsBar({ onLogout }) {
  const [stats, setStats] = useState(null);
  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(`${API_URL}/api/driver-log/stats`, {
          headers: authHeaders(),
        });
        if (res.status === 401) {
          onLogout();
          return;
        }
        if (res.ok) setStats(await res.json());
      } catch {}
    })();
  }, [onLogout]);
  if (!stats) return null;
  return (
    <div className="stats-row">
      <StatCard
        label="Total trips"
        value={stats.total_logs}
        sub="All time"
        accent
      />
      <StatCard
        label="Today's trips"
        value={stats.logs_today}
        sub={`Top: ${stats.top_driver || "—"}`}
      />
      <StatCard
        label="Total distance"
        value={`${Number(stats.total_km || 0).toLocaleString()} km`}
        sub="All logs"
      />
      <StatCard
        label="Active drivers"
        value={stats.active_drivers ?? "—"}
        sub="Registered"
      />
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
//  MAIN APP SHELL
// ══════════════════════════════════════════════════════════════════
function AppShell({ user, onLogout, onUserUpdate }) {
  const [page, setPage] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [showSessionWarn, setShowSessionWarn] = useState(false);
  const sessionRef = useRef();
  const isAdmin = user?.role === "admin";

  const pageLabels = {
    dashboard: "Dashboard",
    drivers: "Driver management",
    logs: isAdmin ? "Trip logs" : "My trips",
    bulk: "Bulk upload",
    profile: "My profile",
    settings: "Settings",
  };

  useEffect(() => {
    const check = () => {
      if (isTokenExpired()) {
        clearInterval(sessionRef.current);
        handleLogout();
        return;
      }
      const remaining = getTokenExpiry() - Date.now();
      setShowSessionWarn(remaining < 5 * 60 * 1000 && remaining > 0);
    };
    check();
    sessionRef.current = setInterval(check, 60000);
    return () => clearInterval(sessionRef.current);
  }, []);

  const handleRefreshSession = async () => {
    try {
      const res = await fetch(`${API_URL}/api/auth/refresh`, {
        method: "POST",
        headers: authHeaders(),
      });
      if (res.ok) {
        const data = await res.json();
        localStorage.setItem("token", data.token);
        localStorage.setItem(
          "tokenExpiry",
          String(Date.now() + 6 * 60 * 60 * 1000),
        );
        setShowSessionWarn(false);
      } else handleLogout();
    } catch {
      handleLogout();
    }
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    localStorage.removeItem("tokenExpiry");
    onLogout();
  };

  const renderPage = () => {
    switch (page) {
      case "dashboard":
        return (
          <div>
            <StatsBar onLogout={handleLogout} />
            <LogsPage user={user} onLogout={handleLogout} />
          </div>
        );
      case "drivers":
        return isAdmin ? <DriversPage onLogout={handleLogout} /> : null;
      case "logs":
        return <LogsPage user={user} onLogout={handleLogout} />;
      case "bulk":
        return isAdmin ? <BulkUploadPage onLogout={handleLogout} /> : null;
      case "profile":
        return (
          <ProfilePage
            user={user}
            onUserUpdate={onUserUpdate}
            onLogout={handleLogout}
          />
        );
      case "settings":
        return <SettingsPage />;
      default:
        return null;
    }
  };

  return (
    <div className="app-shell">
      {showSessionWarn && (
        <SessionWarning
          onRefresh={handleRefreshSession}
          onLogout={handleLogout}
        />
      )}
      <Sidebar
        user={user}
        activePage={page}
        onNavigate={setPage}
        collapsed={!sidebarOpen}
        onToggle={() => setSidebarOpen(!sidebarOpen)}
        onLogout={handleLogout}
      />
      <div className="main-area">
        <Topbar
          title={pageLabels[page] || page}
          user={user}
          onLogout={handleLogout}
        />
        <main className="main-content">{renderPage()}</main>
      </div>
    </div>
  );
}

function SettingsPage() {
  return (
    <div style={{ maxWidth: 500 }}>
      <div className="table-card">
        <div className="settings-title">System preferences</div>
        {[
          ["Email notifications", "Receive alerts for new trip logs"],
          ["Session warning", "Warn 5 min before JWT expiry"],
          ["Show KM on dashboard", "Display total km in stats bar"],
        ].map(([label, desc]) => (
          <div className="settings-row" key={label}>
            <div>
              <div className="settings-label">{label}</div>
              <div className="settings-desc">{desc}</div>
            </div>
            <button
              className="toggle-btn-el on"
              onClick={(e) => e.currentTarget.classList.toggle("on")}
            ></button>
          </div>
        ))}
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
//  ROOT
// ══════════════════════════════════════════════════════════════════
export default function App() {
  const [screen, setScreen] = useState("login");
  const [user, setUser] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const saved = localStorage.getItem("user");
    if (token && saved && Date.now() < getTokenExpiry()) {
      setUser(JSON.parse(saved));
      setScreen("app");
    } else {
      localStorage.removeItem("token");
      localStorage.removeItem("user");
      localStorage.removeItem("tokenExpiry");
    }
  }, []);

  if (screen === "register")
    return <RegisterScreen onGoLogin={() => setScreen("login")} />;
  if (screen === "app")
    return (
      <AppShell
        user={user}
        onLogout={() => {
          setUser(null);
          setScreen("login");
        }}
        onUserUpdate={(u) => setUser(u)}
      />
    );
  return (
    <LoginScreen
      onLogin={(u) => {
        setUser(u);
        setScreen("app");
      }}
      onGoRegister={() => setScreen("register")}
    />
  );
}
